import React from "react";

function App() {
  return (
    <div style={{ padding: "40px", fontFamily: "Arial, sans-serif" }}>
      <h1>Protocol Genesis – System Onboarding</h1>
      <p>
        זה המסך הראשוני של מערכת ניהול המסמכים. בשלב הזה אנחנו רק בודקים
        שה־UI עובד, ובהמשך נוסיף:
      </p>
      <ul>
        <li>רשימת Workspaces</li>
        <li>מסך העלאת קבצים (PDF)</li>
        <li>רשימת קבצים לכל Workspace</li>
      </ul>
    </div>
  );
}

export default App;
